```rust
#[cfg(test)]
mod theme_tests {
    use fastmcp_console::theme::FastMcpTheme;
    use rich_rust::Style;

    #[test]
    fn test_default_theme_has_all_styles() {
        let theme = FastMcpTheme::default();

        // Verify all style methods return valid styles
        assert!(theme.primary_style().has_color());
        assert!(theme.secondary_style().has_color());
        assert!(theme.success_style().has_color());
        assert!(theme.warning_style().has_color());
        assert!(theme.error_style().has_color());
        assert!(theme.info_style().has_color());
        assert!(theme.debug_style().has_color());
        assert!(theme.dim_style().is_dim());
    }

    #[test]
    fn test_theme_color_consistency() {
        let theme = FastMcpTheme::default();

        // Error should be red-ish
        let error_color = theme.error_style().foreground().unwrap();
        assert!(error_color.is_red_family(), "Error color should be in red family");

        // Success should be green-ish
        let success_color = theme.success_style().foreground().unwrap();
        assert!(success_color.is_green_family(), "Success color should be in green family");

        // Warning should be yellow/orange
        let warning_color = theme.warning_style().foreground().unwrap();
        assert!(warning_color.is_yellow_family(), "Warning color should be in yellow family");
    }

