### 2. DisplayContext Tests (context_tests.rs)

```rust
#[cfg(test)]
mod context_tests {
    use fastmcp_console::context::DisplayContext;
    use std::env;

    #[test]
    fn test_agent_context_disables_rich() {
        let ctx = DisplayContext::new_agent();
        assert!(!ctx.should_use_rich());
        assert!(!ctx.should_use_colors());
        assert!(!ctx.should_use_emoji());
    }

    #[test]
    fn test_human_context_enables_rich() {
        let ctx = DisplayContext::new_human();
        assert!(ctx.should_use_rich());
        assert!(ctx.should_use_colors());
    }

    #[test]
    fn test_detect_respects_mcp_client_env() {
        // Save and restore env
        let original = env::var("MCP_CLIENT").ok();

        env::set_var("MCP_CLIENT", "claude-desktop");
        let ctx = DisplayContext::detect();
        assert!(!ctx.should_use_rich(), "MCP_CLIENT should trigger agent mode");

        // Restore
        if let Some(v) = original {
            env::set_var("MCP_CLIENT", v);
        } else {
            env::remove_var("MCP_CLIENT");
        }
    }

    #[test]
    fn test_detect_respects_no_color_env() {
        let original = env::var("NO_COLOR").ok();

        env::set_var("NO_COLOR", "1");
        let ctx = DisplayContext::detect();
        assert!(!ctx.should_use_colors(), "NO_COLOR should disable colors");

        if let Some(v) = original {
            env::set_var("NO_COLOR", v);
        } else {
            env::remove_var("NO_COLOR");
        }
    }

    #[test]
    fn test_detect_respects_force_color_env() {
        // Test FORCE_COLOR=1 overrides even when stdout is not a TTY
    }

    #[test]
    fn test_context_is_clone_and_debug() {
        let ctx = DisplayContext::new_human();
        let _cloned = ctx.clone();
        let _debug = format!("{:?}", ctx);
    }
}
