        let snapshot = stats.snapshot();

        let tc = TestConsole::new();
        let renderer = StatsRenderer::new(/* ... */);
        renderer.render_table(&snapshot, tc.console());

        tc.assert_contains("3"); // Total requests
        tc.assert_contains("66.7%"); // Success rate (2/3)
    }

